external_knowledge:
- "shining stars" metaphorically refers to the top movies;
- "dazzled the audience" implies these movies were successful;
- "bringing in the most gold" metaphorically means generating the highest revenue;
- "under the banner of a specific sovereign land" indicates movies produced within a particular country;
- "country ID 1" refers to a specific country unique identifier.

sql:
SELECT AVG(ur.rating) AS average_rating
FROM user_ratings ur
JOIN (
    SELECT DISTINCT movie_id
    FROM awards
) aw ON ur.movie_id = aw.movie_id;

SELECT movies.name, ratings.rating_name
FROM movies
INNER JOIN ratings ON movies.rating = ratings.rating_id;
